mapper.select:
SELECT /* GrpCdMgmtMapper.selectGrpMgmtList */ GRP_ID /* 그룹 ID */ , GRP_KOR_NM /* 그룹 한글명 */ , GRP_ENG_NM /* 그룹 영어명 */ , GRP_DSC /* 그룹 설명 */ , USG_YN /* 사용 여부 */ , COL_KOR_NM /* 컬럼 한글명 */ , COL_ENG_NM /* 컬럼 영어명 */ , DUTY_SCTN /* 업무 구분 */ , (SELECT CD_DSC FROM CMN_GRP_CD_MST WHERE GRP_ID = 'CMN0023' AND CD_VAL = DUTY_SCTN) as DUTY_SCTN_NM /* 업무 구분명 */ , REMRK /* 비고 */ , REGST_ID /* 등록자 ID */ , RVISN_ID /* 수정자 ID */ FROM CMN_GRP_MST WHERE 1=1
AND (GRP_KOR_NM LIKE '%'||#{grpKorNm}||'%' OR GRP_ID LIKE UPPER('%'||#{grpKorNm}||'%'))
AND DUTY_SCTN = #{dutySctn}
AND USG_YN = #{usgYn}
ORDER BY GRP_ID

mapper.update:
UPDATE CMN_GRP_MST /** GrpCdMgmtMapper.updateGrpMgmt */ 
    SET
     GRP_KOR_NM = #{grpKorNm, jdbcType=VARCHAR} 
    , GRP_ENG_NM = #{grpEngNm, jdbcType=VARCHAR} 
    , GRP_DSC = #{grpDsc, jdbcType=VARCHAR} 
    , USG_YN = #{usgYn, jdbcType=VARCHAR} 
    , COL_KOR_NM = #{colKorNm, jdbcType=VARCHAR} 
    , COL_ENG_NM = #{colEngNm, jdbcType=VARCHAR} 
    , DUTY_SCTN = #{dutySctn, jdbcType=VARCHAR} 
    , REMRK = #{remrk, jdbcType=VARCHAR} 
    , RVISN_ID = #{rvisnId, jdbcType=VARCHAR} 
    , RVISN_DTTM = SYSDATE
 WHERE
     GRP_ID = #{grpId}

